target.css:
:root {
  --board-bg: #1a1f2e;
  --board-border: #2e3650;
  --header-bg: #0f1420;
  --footer-bg: #0f1420;
  --accent-blue: #3b82f6;
  --text-primary: #e8ecf4;
  --text-secondary: #8b95b0;
  --flight-row-bg: #1e2436;
  --flight-row-border: #2a3048;
  --ontime-color: #22c55e;
  --ontime-bg: #14532d;
  --delayed-color: #f59e0b;
  --delayed-bg: #451a03;
  --boarding-color: #60a5fa;
  --boarding-bg: #1e3a5f;
  --cancelled-color: #f87171;
  --cancelled-bg: #450a0a;
  --gate-label-color: #6b7694;
  --airport-code-color: #60a5fa;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.board {
  width: 500px;
  background-color: var(--board-bg);
  border: 2px solid var(--board-border);
  border-radius: 12px;
  overflow: hidden;
}

.board-header {
  background-color: var(--header-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 20px;
  border-bottom: 2px solid var(--board-border);
}

.airport-code {
  font-size: 22px;
  font-weight: 700;
  color: var(--airport-code-color);
  letter-spacing: 2px;
}

.header-info {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.board-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary);
  text-transform: uppercase;
  letter-spacing: 1.5px;
}

.board-time {
  font-size: 11px;
  color: var(--text-secondary);
}

.flight-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 12px;
}

.flight-row {
  display: flex;
  align-items: center;
  gap: 10px;
  background-color: var(--flight-row-bg);
  border: 1px solid var(--flight-row-border);
  border-radius: 8px;
  padding: 10px 14px;
}

.flight-num {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
  width: 56px;
  flex-shrink: 0;
}

.flight-dest {
  font-size: 13px;
  color: var(--text-secondary);
  flex: 1;
}

.flight-time {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  width: 42px;
  text-align: right;
  flex-shrink: 0;
}

.status-badge {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.8px;
  padding: 3px 10px;
  border-radius: 20px;
  flex-shrink: 0;
  width: 72px;
  text-align: center;
}

.status-ontime {
  color: var(--ontime-color);
  background-color: var(--ontime-bg);
}

.status-delayed {
  color: var(--delayed-color);
  background-color: var(--delayed-bg);
}

.status-boarding {
  color: var(--boarding-color);
  background-color: var(--boarding-bg);
}

.status-cancelled {
  color: var(--cancelled-color);
  background-color: var(--cancelled-bg);
}

.board-footer {
  background-color: var(--footer-bg);
  border-top: 2px solid var(--board-border);
  display: flex;
  justify-content: space-around;
  padding: 10px 20px;
}

.gate-info {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.gate-label {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--gate-label-color);
}

.gate-value {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-primary);
}

